/* Lucide icon helper — the fleet's canonical icon component.
 *
 * VENDORED VERBATIM from project-scaffolding. Do NOT edit this file per-app:
 * nothing here varies between apps. Pair it with icons-sprite.html (the inline
 * <symbol> sprite you paste into your page) — this file owns only the tiny
 * convenience of building the <use> markup from JS.
 *
 * Normalized from home-automation's app/webapp/static/icons.js (issue #77 — the
 * fleet's first Lucide adopter).
 *
 * One icon source for the whole PWA: the inline <svg> sprite from
 * icons-sprite.html — a set of <symbol id="i-NAME"> Lucide glyphs (vendored from
 * lucide-static v1.21.0, ISC). Reference a glyph from JS with icon(name); in
 * static markup write <svg class="icon"><use href="#i-NAME"></use></svg>.
 *
 * The sprite is inline (not an external /static/icons.svg) on purpose: iOS
 * Safari does not resolve external <use href="file.svg#id"> references, so the
 * symbols must ship in-document (see icons-sprite.html and the README). Stroke
 * styling lives on the `.icon` CSS class and is inherited into the <use> shadow
 * tree; fill:none lives on each <symbol> so the few filled glyphs (e.g. the
 * palette dots) keep their fill. Required design tokens: none — icons inherit
 * currentColor, so they recolor for free in light + dark.
 */

'use strict';

/**
 * Build the markup for a sprite glyph.
 *
 * @param {string} name        the glyph name without the `i-` prefix (e.g. 'house').
 * @param {string} [extraClass] extra CSS class(es) appended after `icon`.
 * @returns {string} an `<svg class="icon …"><use href="#i-NAME"></use></svg>` string.
 */
export function icon(name, extraClass) {
  const cls = 'icon' + (extraClass ? ' ' + extraClass : '');
  return '<svg class="' + cls + '" aria-hidden="true"><use href="#i-' + name + '"></use></svg>';
}
